CREATE OR REPLACE FUNCTION fpb_calc_prin_pending_amount (as_conno char, adt_opdate timestamp(0)) RETURNS bigint AS $body$
DECLARE

ldc_pending bigint;
ldc_period_payment_amount bigint;
ls_pay_type_code sc_lon_m_contract.loan_payment_type_code%type;
ls_keeping_status char;
li_year integer;
li_month integer;
ldc_money_amount bigint;
ldt_calc_to timestamp(0);
ldc_return bigint;
ldc_int_calc bigint;

BEGIN
-- จะใช้ในสัญญานั้นสถานะประมวลผล เท่านั้น
  begin
    select period_payment_amount , keeping_status ,loan_payment_type_code ,keeping_year ,keeping_month
    into STRICT   ldc_period_payment_amount ,ls_keeping_status ,ls_pay_type_code ,li_year , li_month
    from  sc_lon_m_contract ,sc_lon_m_loan_card
    where sc_lon_m_contract.loan_contract_no = sc_lon_m_loan_card.loan_contract_no
    and   sc_lon_m_contract.loan_contract_no = as_conno
;
    exception when no_data_found then return 0;
              when others then return 0;
  end;
  if trim(both ls_pay_type_code) = '02' then
    begin
      select sc_kep_t_monthly_receive_det.money_amount ,sc_kep_t_monthly_receive_det.int_to
      into STRICT  ldc_money_amount,ldt_calc_to
      from sc_kep_t_monthly_receive , sc_kep_t_monthly_receive_det
      where sc_kep_t_monthly_receive.receive_year = sc_kep_t_monthly_receive_det.receive_year
      and   sc_kep_t_monthly_receive.receive_month = sc_kep_t_monthly_receive_det.receive_month
      and   sc_kep_t_monthly_receive.membership_no = sc_kep_t_monthly_receive_det.membership_no
      and   sc_kep_t_monthly_receive.receive_year = li_year
      and   sc_kep_t_monthly_receive.receive_month = li_month
      and   trim(both sc_kep_t_monthly_receive_det.receive_description) = trim(both as_conno)
;
      exception when no_data_found then return 0;
              when others then return 0;
    end;
  end if;
  if ldc_money_amount > 0 then
      ldc_int_calc := pka_lon_intsrv.fp_calint(as_conno ,ldt_calc_to,ldc_money_amount,adt_opdate);
      ldc_return := ldc_money_amount - ldc_int_calc;
  end if;
  RETURN ldc_return;
 exception WHEN others then return 0;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
